function killCurrentProc(): void {
  if (!currentProc) return;
  try {
    currentProc.kill();
  } catch {}
}

function archiveCompletedTasks(): void {
  let content: string;
  try {
    content = readFileSync(CONFIG.progressFile, 'utf-8');
  } catch {
    return;
  }

  const estimatedTokens = Math.ceil(content.length / 4);
  if (estimatedTokens <= TOKEN_THRESHOLD) return;

  const blocks = content.split(new RegExp(`^${SEPARATOR}$`, 'm'));
  const completed: string[] = [];
  const pending: string[] = [];

  for (const block of blocks) {
    const trimmed = block.trim();
    if (!trimmed) continue;

    if (/^- \[x\]/m.test(trimmed)) {
      completed.push(trimmed);
    } else {
      pending.push(trimmed);
    }
  }

  if (completed.length === 0) return;

  const timestamp = new Date().toISOString().replace(/[:.]/g, '').slice(0, 15);
  const archivePath = `${LOG_DIR}/${timestamp}-progress.txt`;
  writeFileSync(archivePath, completed.join(`\n\n${SEPARATOR}\n\n`) + '\n');

