  1→#!/usr/bin/env bun
  2→
  3→/**
  4→ * Ralph Loop - Automated Claude Code Task Executor
  5→ *
  6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7→ * - Fresh context per iteration (new Claude instance each time)
  8→ * - Memory persists through files only (git, progress.txt)
  9→ * - One task per iteration
 10→ * - Completion signal terminates loop
 11→ *
 12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13→ *
 14→ * @see https://ghuntley.com/ralph/
 15→ */
 16→
 17→import {
 18→  appendFileSync,
 19→  mkdirSync,
 20→  readFileSync,
 21→  renameSync,
 22→  writeFileSync,
 23→} from 'node:fs';
 24→import { createAsyncPlugin, createSyncPlugin } from 'plugin-hooks';
 25→import { chalk } from 'zx';
 26→
 27→const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 28→const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 29→
 30→function parsePositiveInt(arg: string | undefined, fallback: number): number {
 31→  const parsed = parseInt(arg ?? String(fallback), 10);
 32→  if (isNaN(parsed) || parsed <= 0) {
 33→    console.error(`Error: expected a positive integer, got "${arg}"`);
 34→    process.exit(1);
 35→  }
 36→  return parsed;
 37→}
 38→
 39→const LOG_DIR = './.loop';
 40→const SEPARATOR = '-'.repeat(80);
 41→const TOKEN_THRESHOLD = 1000;
 42→mkdirSync(LOG_DIR, { recursive: true });
 43→
 44→const CONFIG = Object.freeze({
 45→  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 46→  delayBetweenIterations: 1_000,
 47→  progressFile: './.claude/progress.txt',
 48→  iterationTimeout: 600_000,
 49→  logFlushInterval: 2_000,
 50→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 51→});
 52→
 53→interface IterationResult {
 54→  output: string;
 55→  exitCode: number;
 56→  timedOut: boolean;
 57→}
 58→
 59→interface RalphStatus {
 60→  exit: boolean;
 61→  task: string;
 62→  remaining: number;
 63→}
 64→
 65→interface IterationContext {
 66→  iteration: number;
 67→  maxIterations: number;
 68→  logPath: string;
 69→}
 70→
 71→interface FailureContext extends IterationContext {
 72→  exitCode: number;
 73→  consecutiveFailures: number;
 74→}
 75→
 76→interface BackoffContext extends FailureContext {
 77→  backoffMs: number;
 78→}
 79→
 80→/**
 81→ * Plugin hooks for the Ralph Loop lifecycle.
 82→ *
 83→ * All hooks use plugin-hooks middleware pipelines:
 84→ * - Async plugins: middleware receives (value, context, self). Return undefined to pass through,
 85→ *   return a value to replace. Errors propagate from dispatch().
 86→ * - `resolveStatus`: waterfall — return a modified `RalphStatus | null` to override,
 87→ *   or return undefined to pass through.
 88→ * - `shouldSkipBackoff`: uses `returnOnFirst` — first middleware that returns `true`
 89→ *   short-circuits and skips backoff.
 90→ * - `cleanup`: synchronous — only sync side effects are guaranteed before `process.exit`.
 91→ */
 92→const hooks = {
 93→  loopStart: createAsyncPlugin<typeof CONFIG>(),
 94→  iterationStart: createAsyncPlugin<IterationContext>(),
 95→  iterationSuccess: createAsyncPlugin<IterationResult, IterationContext>(),
 96→  iterationTimeout: createAsyncPlugin<IterationResult, IterationContext>(),
 97→  iterationFailure: createAsyncPlugin<IterationResult, FailureContext>(),
 98→  resolveStatus: createAsyncPlugin<RalphStatus | null, string>(),
 99→  taskComplete: createAsyncPlugin<RalphStatus, IterationContext>(),
100→  allTasksComplete: createAsyncPlugin<RalphStatus, number>(),
101→  shouldSkipBackoff: createAsyncPlugin<boolean, BackoffContext>({
102→    returnOnFirst: true,
103→  }),
104→  loopEnd: createAsyncPlugin<number>(),
105→  cleanup: createSyncPlugin<string>(),
106→};
