308→  message?: {
309→    role?: string;
310→    content?: ContentBlock[];
311→  };
312→  content?: ContentBlock[];
313→}
314→
315→function parseRalphStatus(output: string): RalphStatus | null {
316→  const marker = output.lastIndexOf('RALPH_STATUS:');
317→  if (marker === -1) return null;
318→
319→  const jsonStart = output.indexOf('{', marker);
320→  if (jsonStart === -1) return null;
321→
322→  let depth = 0;
323→  for (let i = jsonStart; i < output.length; i++) {
324→    if (output[i] === '{') depth++;
325→    if (output[i] === '}') depth--;
326→    if (depth === 0) {
327→      try {
328→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
329→        if (typeof parsed.exit === 'boolean') {
330→          return parsed as RalphStatus;
331→        }
332→      } catch {}
333→      return null;
334→    }
335→  }
336→  return null;
337→}
338→
339→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
340→
341→function killCurrentProc(): void {
342→  if (!currentProc) return;
343→  try {
344→    currentProc.kill();
345→  } catch {}
346→}
347→
348→function archiveCompletedTasks(): void {
349→  let content: string;
350→  try {
351→    content = readFileSync(CONFIG.progressFile, 'utf-8');
352→  } catch {
353→    return;
354→  }
355→
356→  const estimatedTokens = Math.ceil(content.length / 4);
357→  if (estimatedTokens <= TOKEN_THRESHOLD) return;
358→
359→  const blocks = content.split(new RegExp(`^${SEPARATOR}$`, 'm'));
360→  const completed: string[] = [];
361→  const pending: string[] = [];
362→
363→  for (const block of blocks) {
364→    const trimmed = block.trim();
365→    if (!trimmed) continue;
366→
367→    if (/^- \[x\]/m.test(trimmed)) {
368→      completed.push(trimmed);
369→    } else {
370→      pending.push(trimmed);
371→    }
372→  }
373→
374→  if (completed.length === 0) return;
375→
376→  const timestamp = new Date().toISOString().replace(/[:.]/g, '').slice(0, 15);
377→  const archivePath = `${LOG_DIR}/${timestamp}-progress.txt`;
378→  writeFileSync(archivePath, completed.join(`\n\n${SEPARATOR}\n\n`) + '\n');
379→
380→  const newContent = pending.join(`\n\n${SEPARATOR}\n\n`) + '\n';
381→  writeFileSync(CONFIG.progressFile, newContent);
382→
383→  syslog(
384→    `Archived ${completed.length} completed task(s) to ${archivePath}`,
385→    'blue',
386→  );
387→}
388→
389→async function checkDependencies(): Promise<void> {
390→  const result = await Bun.$`which claude`.quiet().nothrow();
391→  if (result.exitCode !== 0) {
392→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
393→    process.exit(1);
394→  }
395→
396→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
397→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
398→    process.exit(1);
399→  }
400→}
401→
402→async function runIteration(): Promise<IterationResult> {
403→  syslog('Executing Claude Code...');
404→
405→  const proc = Bun.spawn(
406→    [
407→      'claude',
408→      '-p',
409→      TASK_PROMPT,
410→      '--verbose',
411→      '--debug',
412→      '--dangerously-skip-permissions',
413→      '--output-format',
414→      'stream-json',
415→      '--include-partial-messages',
416→      '--model=opus',
417→    ],
418→    {
419→      cwd: process.cwd(),
420→      env: process.env,
421→      stdout: 'pipe',
422→      stderr: 'inherit',
423→    },
424→  );
425→
426→  currentProc = proc;
427→
428→  const chunks: string[] = [];
429→  let timedOut = false;
430→  const decoder = new TextDecoder();
431→  let buffer = '';
432→  let blockHasContent = false;
433→
434→  const timeoutId = setTimeout(() => {
435→    timedOut = true;
436→    syslog('Iteration timeout reached. Killing process...', 'yellow');
437→    killCurrentProc();
438→  }, CONFIG.iterationTimeout);
439→
440→  const reader = proc.stdout.getReader();
441→
442→  try {
443→    while (true) {
444→      const { done, value } = await reader.read();
445→      if (done) break;
446→
447→      buffer += decoder.decode(value, { stream: true });
448→
449→      const lines = buffer.split('\n');
450→      buffer = lines.pop() || '';
451→
452→      for (const line of lines) {
453→        if (!line.trim()) continue;
454→
455→        let msg: StreamMessage;
456→        try {
457→          msg = JSON.parse(line);
458→        } catch {
459→          continue;
460→        }
461→
462→        if (msg.type === 'stream_event') {
463→          const evt = msg.event;
464→          if (!evt) continue;
465→
466→          if (evt.type === 'content_block_start') {
467→            blockHasContent = false;
468→          } else if (evt.type === 'content_block_delta') {
469→            const text = evt.delta?.text;
470→            if (text) {
471→              print(text);
472→              chunks.push(text);
473→              blockHasContent = true;
474→            }
475→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
476→            print('\n');
477→            chunks.push('\n');
478→            blockHasContent = false;
479→          }
480→          continue;
481→        }
482→
483→        if (msg.type === 'assistant' || msg.type === 'message') {
484→          const blocks = msg.message?.content ?? msg.content;
485→          if (!Array.isArray(blocks)) continue;
486→
487→          for (const block of blocks) {
488→            if (block.type === 'text' && block.text && chunks.length === 0) {
489→              print(block.text);
490→              chunks.push(block.text);
491→              print('\n');
492→              chunks.push('\n');
493→            }
494→          }
495→          continue;
496→        }
497→
498→        if (msg.type === 'user') {
499→          const blocks = msg.message?.content ?? msg.content;
500→          if (!Array.isArray(blocks)) continue;
501→
502→          for (const block of blocks) {
503→            if (block.type === 'tool_result' && block.content) {
504→              const rawContent =
505→                typeof block.content === 'string'
506→                  ? block.content
507→                  : block.content
508→                      .map(c => c.text ?? '')
509→                      .filter(Boolean)
510→                      .join('\n');
511→
512→              if (!rawContent) continue;
513→
514→              let trimmed = rawContent.trim().slice(0, 320);
515→
516→              const toolResult =
517→                trimmed && trimmed !== rawContent
518→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
519→                  : rawContent;
520→
521→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
522→              chunks.push('\n', rawContent, '\n');
523→            }
524→          }
525→          continue;
526→        }
527→
528→        if (msg.type === 'result' && msg.result) {
529→          if (chunks.length === 0) {
530→            chunks.push(msg.result);
531→          }
532→        }
533→      }
534→    }
535→
536→    if (buffer.trim()) {
537→      try {
538→        const msg: StreamMessage = JSON.parse(buffer);
539→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
540→          chunks.push(msg.result);
541→        }
542→      } catch {}
543→    }
544→  } finally {
545→    clearTimeout(timeoutId);
546→    reader.releaseLock();
547→    currentProc = null;
548→    logBuffer.flush();
549→  }
550→
551→  const output = chunks.join('');
552→
553→  if (timedOut) {
554→    return {
555→      output,
556→      exitCode: 124,
557→      timedOut: true,
558→    };
559→  }
560→
561→  const exitCode = await proc.exited;
562→  println();
563→  return {
564→    output,
565→    exitCode,
566→    timedOut: false,
567→  };
568→}
569→
570→function printHeader(): void {
571→  println();
572→  println('==========================================', 'blue');
573→  println('   Ralph Loop - Bun.js Edition', 'blue');
574→  println('==========================================', 'blue');
575→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
576→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
577→  println(
578→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
579→  );
580→  println(
581→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
582→  );
583→  println();
584→}
585→
586→async function main(): Promise<void> {
587→  let cleanupCalled = false;
588→
589→  const cleanup = (signal: string) => {
590→    if (cleanupCalled) return;
591→    cleanupCalled = true;
592→    try {
593→      hooks.cleanup.dispatch(signal, undefined);
594→    } catch (err) {
595→      console.error(`[cleanup hook error] ${err}`);
596→    }
597→    println();
598→    syslog(`Interrupted by ${signal}. Cleaning up...`);
599→    killCurrentProc();
600→    logBuffer.dispose();
601→    process.exit(signal === 'SIGINT' ? 130 : 143);
602→  };
603→
604→  process.on('SIGINT', () => cleanup('SIGINT'));
605→  process.on('SIGTERM', () => cleanup('SIGTERM'));
606→
607→  await checkDependencies();
608→
609→  printHeader();
610→  syslog('Starting automated task loop...');
611→
612→  await dispatchSafe(hooks.loopStart, 'loopStart', CONFIG, undefined);
613→
614→  let consecutiveFailures = 0;
615→  let iteration = 0;
616→  const BACKOFF_BASE_MS = 60_000;
617→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
618→
619→  while (iteration < CONFIG.maxIterations) {
620→    archiveCompletedTasks();
621→
622→    const attemptNum = iteration + 1;
623→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
624→
625→    const iterCtx: IterationContext = {
626→      iteration: attemptNum,
627→      maxIterations: CONFIG.maxIterations,
628→      logPath: logBuffer.currentPath(),
629→    };
630→
631→    println();
632→    println('==========================================', 'green');
633→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
634→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
635→    println('==========================================', 'green');
636→    println();
637→
638→    await dispatchSafe(
639→      hooks.iterationStart,
640→      'iterationStart',
641→      iterCtx,
642→      undefined,
643→    );
644→
645→    const result = await runIteration();
646→    const { output, exitCode, timedOut } = result;
647→
648→    if (exitCode === 0) {
649→      syslog('Claude Code completed successfully', 'green');
650→      consecutiveFailures = 0;
651→      await dispatchSafe(
652→        hooks.iterationSuccess,
653→        'iterationSuccess',
654→        result,
655→        iterCtx,
656→      );
657→    } else if (timedOut) {
658→      syslog(
659→        'Iteration timed out — progress may persist in progress.txt',
660→        'yellow',
661→      );
662→      consecutiveFailures = 0;
663→      await dispatchSafe(
664→        hooks.iterationTimeout,
665→        'iterationTimeout',
666→        result,
667→        iterCtx,
668→      );
669→    } else {
670→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
671→      consecutiveFailures++;
672→
673→      const failCtx: FailureContext = {
674→        ...iterCtx,
675→        exitCode,
676→        consecutiveFailures,
677→      };
678→      await dispatchSafe(
679→        hooks.iterationFailure,
680→        'iterationFailure',
681→        result,
682→        failCtx,
683→      );
684→
685→      const backoffMs = Math.min(
686→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
687→        BACKOFF_MAX_MS,
688→      );
689→      const backoffMin = (backoffMs / 60_000).toFixed(1);
690→
691→      const backoffCtx: BackoffContext = {
692→        ...failCtx,
693→        backoffMs,
694→      };
695→      const skipBackoff = await dispatchSafe(
696→        hooks.shouldSkipBackoff,
697→        'shouldSkipBackoff',
698→        false,
699→        backoffCtx,
700→      );
701→
702→      if (skipBackoff === true) {
703→        syslog('Backoff skipped by hook', 'yellow');
704→      } else {
705→        println();
706→        println('==========================================', 'yellow');
707→        syslog(
708→          `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
709→          'yellow',
710→        );
711→        println('==========================================', 'yellow');
712→        await Bun.sleep(backoffCtx.backoffMs);
713→      }
714→      continue;
715→    }
716→
717→    iteration++;
718→
719→    const rawStatus = parseRalphStatus(output);
720→    const status = await dispatchSafe(
721→      hooks.resolveStatus,
722→      'resolveStatus',
723→      rawStatus,
724→      output,
725→    );
726→    const taskSlug = status
727→      ? slugify(status.task)
728→      : timedOut
729→        ? 'timeout'
730→        : 'no-status';
731→    logBuffer.renameFile(logFilePath(taskSlug));
732→
733→    if (status?.exit) {
734→      await dispatchSafe(
735→        hooks.allTasksComplete,
736→        'allTasksComplete',
737→        status,
738→        iteration,
739→      );
740→      println();
741→      println('==========================================', 'green');
742→      syslog('ALL TASKS COMPLETED!', 'green');
743→      syslog(`Final task:      ${status.task}`, 'green');
744→      syslog(`Remaining:       ${status.remaining}`, 'green');
745→      syslog(`Total iterations: ${iteration}`, 'green');
746→      println('==========================================', 'green');
747→      logBuffer.dispose();
748→      process.exit(0);
749→    }
750→
751→    if (status) {
752→      await dispatchSafe(hooks.taskComplete, 'taskComplete', status, iterCtx);
753→      syslog(
754→        `Task done: "${status.task}" — ${status.remaining} remaining`,
755→        'blue',
756→      );
757→    } else if (!timedOut && exitCode === 0) {
758→      syslog(
759→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
760→        'yellow',
761→      );
762→    }
763→
764→    if (iteration < CONFIG.maxIterations) {
765→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
766→      println();
767→      syslog(`Waiting ${delaySec}s before next iteration...`);
768→      await Bun.sleep(CONFIG.delayBetweenIterations);
769→    }
770→  }
771→
772→  await dispatchSafe(hooks.loopEnd, 'loopEnd', iteration, undefined);
773→
774→  println();
775→  println('==========================================', 'red');
776→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
777→  syslog('Loop stopped — tasks may still be pending', 'red');
778→  println('==========================================', 'red');
779→  logBuffer.dispose();
780→  process.exit(1);
781→}
782→
783→if (import.meta.main) {
784→  main();
785→}
